#include <stdio.h>
#include <string.h>
#define MAX 100005
int main() {
    int n, m, k;
    scanf("%d %d %d", &n, &m, &k);
    char kingdom[n][m];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            kingdom[i][j] = 'J';
        }
    }
    for (int i = 0; i < k; i++) {
        int row, l, r;
        char enemy[11];
        scanf("%d %d %d %s", &row, &l, &r, enemy);
        row--;
        for (int j = l - 1; j < r; j++) {
            kingdom[row][j] = enemy[0];
        }
    }
    int maxCount = 0;
    int count = 0;
    for (int j = 0; j < m; j++) {
        int distinct[256] = {0};
        int localCount = 0;
        for (int i = 0; i < n; i++) {
            if (!distinct[kingdom[i][j]]) {
                distinct[kingdom[i][j]] = 1;
                localCount++;
            }
        }
        if (localCount > maxCount) {
            maxCount = localCount;
            count = 1;
        } else if (localCount == maxCount) {
            count++;
        }
    }
    printf("%d %d\n", count, maxCount);
    return 0;
}

