import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int m = sc.nextInt();
        int k = sc.nextInt();
        char[][] kingdom = new char[n][m];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                kingdom[i][j] = 'J';
            }
        }
        for (int i = 0; i < k; i++) {
            int row = sc.nextInt() - 1;
            int l = sc.nextInt() - 1;
            int r = sc.nextInt();
            String enemy = sc.next();
            for (int j = l; j < r; j++) {
                kingdom[row][j] = enemy.charAt(0);
            }
        }
        int maxCount = 0;
        int count = 0;
        for (int j = 0; j < m; j++) {
            boolean[] distinct = new boolean[256];
            int localCount = 0;
            for (int i = 0; i < n; i++) {
                if (!distinct[kingdom[i][j]]) {
                    distinct[kingdom[i][j]] = true;
                    localCount++;
                }
            }
            if (localCount > maxCount) {
                maxCount = localCount;
                count = 1;
            } else if (localCount == maxCount) {
                count++;
            }
        }
        System.out.println(count + " " + maxCount);
    }
}

