const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const n = +lines[idx++];
const m = +lines[idx++].split(' ')[1];
const k = +lines[idx++].split(' ')[2];
const kingdom = Array(n).fill(0).map(() => Array(m).fill('J'));
for (let i = 0; i < k; i++) {
    const [row, l, r, enemy] = lines[idx++].split(' ');
    for (let j = +l - 1; j < +r; j++) {
        kingdom[+row - 1][j] = enemy[0];
    }
}
let maxCount = 0;
let count = 0;
for (let j = 0; j < m; j++) {
    const distinct = new Set();
    let localCount = 0;
    for (let i = 0; i < n; i++) {
        if (!distinct.has(kingdom[i][j])) {
            distinct.add(kingdom[i][j]);
            localCount++;
        }
    }
    if (localCount > maxCount) {
        maxCount = localCount;
        count = 1;
    } else if (localCount === maxCount) {
        count++;
    }
}
